LATIN = re.compile(r"[A-Za-z]")


def main() -> None:
    text = SRC.read_text(encoding="utf-8")
    text = text.replace("\u05d7\u05d5\u05e8\u05d10589", "\u05d7\u05d5\u05e8\u05d1\u05df \u05d4\u05d1\u05d9\u05ea")
    text = text.replace("\u05d7\u05d5\u05e8\u05d1\u0589", "\u05d7\u05d5\u05e8\u05d1\u05df \u05d4\u05d1\u05d9\u05ea")
    SRC.write_text(text, encoding="utf-8")

    spec = importlib.util.spec_from_file_location("_write_edu_he_mod", SRC)
    mod = importlib.util.module_from_spec(spec)
    assert spec.loader is not None
    spec.loader.exec_module(mod)
    translations: list[str] = list(mod.TRANSLATIONS)
    if len(translations) == 31:
        translations.extend(EXTRA)
    elif len(translations) != 37:
        raise ValueError(f"Expected 31 or 37 translations, got {len(translations)}")

    for i, tr in enumerate(translations, 1):
        sample = tr.replace("$bedikatLeadIn", "")
        if LATIN.search(sample):
            raise ValueError(f"Entry {i} has Latin: {set(LATIN.findall(sample))}")

    if len(translations) != len(KEYS):
        raise ValueError(f"{len(KEYS)} keys vs {len(translations)} translations")

    out = dict(zip(KEYS, translations, strict=True))
    OUT.write_text(json.dumps(out, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    lines = len(OUT.read_text(encoding="utf-8").splitlines())
    print(f"Wrote {OUT.name}: {len(out)} keys, {lines} lines")


